def check_winner(self, player_hand, dealer_hand):
    """
        खेल के विजेता का निर्धारण करता है खिलाड़ी और डीलर के हाथ के मानों की तुलना करके।
        नियम:
        यदि दोनों खिलाड़ियों के हाथ के मान 21 के बराबर या उससे कम हैं, तो विजेता वह है जिसका हाथ का मान 21 के करीब है।
        अन्यथा, विजेता वह है जिसके पास कम हाथ का मान है।
        :param player_hand: सूची
        :param dealer_hand: सूची
        :return: खेल का परिणाम, केवल दो निश्चित स्ट्रिंग: 'Dealer wins' या 'Player wins'
        >>> black_jack_game.check_winner(['QD', '9D', 'JC', 'QH', 'AS'], ['QD', '9D', 'JC', 'QH', '2S'])
        'Player wins'
        """
    player_value = self.calculate_hand_value(player_hand)
    dealer_value = self.calculate_hand_value(dealer_hand)
    if player_value <= 21 and dealer_value <= 21:
        if player_value > dealer_value:
            return 'Player wins'
        elif dealer_value > player_value:
            return 'Dealer wins'
        else:
            return 'Dealer wins'
    elif player_value > 21 and dealer_value > 21:
        if player_value < dealer_value:
            return 'Player wins'
        else:
            return 'Dealer wins'
    elif player_value > 21:
        return 'Dealer wins'
    else:
        return 'Player wins'

def add_book(self, title, quantity=1):
    """
        एक या एक से अधिक किताबों को इन्वेंटरी में जोड़ें जो किताब के शीर्षक के अनुसार क्रमबद्ध है।
        :param title: str, किताब का शीर्षक
        :param quantity: int, डिफ़ॉल्ट मान 1 है।
        """
    if title in self.inventory:
        self.inventory[title] += quantity
    else:
        self.inventory[title] = quantity

def remove_book(self, title, quantity):
    """
        इन्वेंटरी से एक या कई किताबें हटाएं जो किताब के शीर्षक द्वारा क्रमबद्ध है।
        अमान्य इनपुट मिलने पर झूठा उठाएं।
        :param title: str, किताब का शीर्षक
        :param quantity: int
        """
    if not isinstance(title, str):
        raise ValueError('Title must be a string')
    if not isinstance(quantity, int) or quantity <= 0:
        raise ValueError('Quantity must be a positive integer')
    if title not in self.inventory:
        raise ValueError(f"Book '{title}' not found in inventory")
    if self.inventory[title] < quantity:
        raise ValueError(f"Cannot remove {quantity} copies of '{title}'. Only {self.inventory[title]} available")
    self.inventory[title] -= quantity
    if self.inventory[title] == 0:
        del self.inventory[title]

def calculate(self, expression):
    """
        दिए गए एक्सप्रेशन की वैल्यू कैलकुलेट करें।

        :param expression: string, दिया गया एक्सप्रेशन
        :return: अगर सफल रहा, तो एक्सप्रेशन की वैल्यू रिटर्न करता है; नहीं तो None रिटर्न करता है

        >>> calculator = Calculator()
        >>> calculator.calculate('1+2-3')
        0.0
        """
    if not expression:
        return None
    operand_stack = []
    operator_stack = []
    i = 0
    n = len(expression)
    while i < n:
        char = expression[i]
        if char.isdigit() or char == '.':
            j = i
            while j < n and (expression[j].isdigit() or expression[j] == '.'):
                j += 1
            try:
                num = float(expression[i:j])
            except ValueError:
                return None
            operand_stack.append(num)
            i = j
        elif char in self.operators:
            while operator_stack and self.precedence(operator_stack[-1]) >= self.precedence(char):
                operand_stack, operator_stack = self.apply_operator(operand_stack, operator_stack)
            operator_stack.append(char)
            i += 1
        elif char == '(':
            operator_stack.append(char)
            i += 1
        elif char == ')':
            while operator_stack and operator_stack[-1] != '(':
                operand_stack, operator_stack = self.apply_operator(operand_stack, operator_stack)
            if operator_stack and operator_stack[-1] == '(':
                operator_stack.pop()
            else:
                return None
            i += 1
        elif char.isspace():
            i += 1
        else:
            return None
    while operator_stack:
        if operator_stack[-1] == '(':
            return None
        operand_stack, operator_stack = self.apply_operator(operand_stack, operator_stack)
    if len(operand_stack) == 1 and (not operator_stack):
        return operand_stack[0]
    else:
        return None

def apply_operator(self, operand_stack, operator_stack):
    """
        ऑपरेटर स्टैक के शीर्ष पर मौजूद ऑपरेटर का उपयोग करके ऑपरेशन को ऑपरेटर स्टैक के शीर्ष पर मौजूद दो संख्याओं पर लागू करें, और परिणामों को ऑपरेटर स्टैक के शीर्ष पर स्टोर करें
        :param operand_stack:list
        :param operator_stack:list
        :return: अपडेटेड operand_stack और operator_stack
        >>> calculator = Calculator()
        >>> calculator.apply_operator([1, 2, 3], ['+', '-'])
        ([1, -1], ['-'])
        """
    if len(operand_stack) < 2 or not operator_stack:
        return (operand_stack, operator_stack)
    operator = operator_stack.pop()
    b = operand_stack.pop()
    a = operand_stack.pop()
    try:
        result = self.operators[operator](a, b)
        operand_stack.append(result)
    except (ZeroDivisionError, KeyError):
        return (operand_stack, operator_stack)
    return (operand_stack, operator_stack)

def register_student(self, student):
    """
        सिस्टम में एक छात्र को पंजीकृत करें, छात्र को छात्रों की सूची में जोड़ें, यदि छात्र पहले से पंजीकृत है, तो 0 लौटाएं, अन्यथा 1 लौटाएं
        """
    for existing_student in self.students:
        if existing_student['name'] == student['name']:
            return 0
    self.students.append(student)
    return 1

def get_most_popular_class_in_major(self, major):
    """
        उस मेजर में सबसे अधिक नामांकित कक्षा प्राप्त करें।
        :return  इस मेजर में सबसे लोकप्रिय कक्षा का एक स्ट्रिंग
        >>> registration_system = ClassRegistrationSystem()
        >>> registration_system.students = [{"name": "John", "major": "Computer Science"},
                                             {"name": "Bob", "major": "Computer Science"},
                                             {"name": "Alice", "major": "Computer Science"}]
        >>> registration_system.students_registration_classes = {"John": ["Algorithms", "Data Structures"],
                                            "Bob": ["Operating Systems", "Data Structures", "Algorithms"]}
        >>> registration_system.get_most_popular_class_in_major("Computer Science")
        "Data Structures"
        """
    class_counts = {}
    students_in_major = self.get_students_by_major(major)
    for student_name in students_in_major:
        if student_name in self.students_registration_classes:
            for class_name in self.students_registration_classes[student_name]:
                class_counts[class_name] = class_counts.get(class_name, 0) + 1
    if not class_counts:
        return ''
    most_popular_class = max(class_counts, key=class_counts.get)
    return most_popular_class

